import{c as s,Q as e,j as i,m as t}from"./chunks/framework.CXOR23sH.js";const k=JSON.parse('{"title":"Grafana Observability Stack","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/grafana-stack.md","filePath":"showcases/grafana-stack.md","lastUpdated":1781379578000}'),n={name:"showcases/grafana-stack.md"};function r(o,a,h,l,d,p){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="grafana-observability-stack" tabindex="-1">Grafana Observability Stack <a class="header-anchor" href="#grafana-observability-stack" aria-label="Permalink to &quot;Grafana Observability Stack&quot;">​</a></h1><p>This showcase deploys a lightweight observability stack — <strong>Prometheus</strong>, <strong>Grafana Tempo</strong>, and <strong>Grafana</strong> — to the <code>monitoring</code> namespace. It serves as the shared monitoring foundation for other showcases like <a href="./kong-ai-gateway.html">Kong AI Gateway</a> and <a href="./kuma.html">Kuma Service Mesh</a>.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Source</th><th>Namespace</th></tr></thead><tbody><tr><td>Prometheus</td><td>Helm chart <code>prometheus-community/prometheus</code></td><td><code>monitoring</code></td></tr><tr><td>Grafana Tempo</td><td>Helm chart <code>grafana/tempo</code></td><td><code>monitoring</code></td></tr><tr><td>Grafana</td><td>Helm chart <code>grafana/grafana</code></td><td><code>monitoring</code></td></tr></tbody></table><h2 id="preconditions" tabindex="-1">Preconditions <a class="header-anchor" href="#preconditions" aria-label="Permalink to &quot;Preconditions&quot;">​</a></h2><ul><li>k3d cluster deployed</li><li><code>helm</code> CLI installed</li></ul><h2 id="dns-preparation" tabindex="-1">DNS preparation <a class="header-anchor" href="#dns-preparation" aria-label="Permalink to &quot;DNS preparation&quot;">​</a></h2><p>Add the following entry to <code>/etc/hosts</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>127.0.0.1 grafana.example.com</span></span></code></pre></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/grafana-stack</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>The script:</p><ol><li>Creates the <code>monitoring</code> namespace with Kuma sidecar injection enabled</li><li>Adds the <code>prometheus-community</code> and <code>grafana</code> Helm repositories</li><li>Deploys Prometheus, Tempo, and Grafana via Helm</li><li>Waits for all deployments to be ready</li><li>Applies an HTTPRoute to expose Grafana at <code>https://grafana.example.com:8081</code></li></ol><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>URL</th><th>Credentials</th></tr></thead><tbody><tr><td>Grafana</td><td><code>https://grafana.example.com:8081</code></td><td>admin / admin</td></tr></tbody></table><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Any scrape target ──▶ Prometheus ──┐</span></span>
<span class="line"><span>                          ▲         ├──▶ Grafana</span></span>
<span class="line"><span>Any OTLP source ────▶ Tempo ───────┘</span></span>
<span class="line"><span>  (service graph metrics remote write)</span></span></code></pre></div><h3 id="prometheus" tabindex="-1">Prometheus <a class="header-anchor" href="#prometheus" aria-label="Permalink to &quot;Prometheus&quot;">​</a></h3><p>Prometheus is deployed as a minimal scrape engine with no alertmanager, node-exporter, or kube-state-metrics. It also acts as a remote write receiver, so Tempo can push generated service graph and span metrics back into it.</p><p>Other showcases register their own scrape targets by extending <code>prometheus-values.yaml</code> or deploying ServiceMonitor resources.</p><h3 id="grafana-tempo" tabindex="-1">Grafana Tempo <a class="header-anchor" href="#grafana-tempo" aria-label="Permalink to &quot;Grafana Tempo&quot;">​</a></h3><p>Tempo runs in single-binary mode and receives traces via OTLP:</p><table tabindex="0"><thead><tr><th>Protocol</th><th>Endpoint</th></tr></thead><tbody><tr><td>OTLP HTTP</td><td><code>:4318</code></td></tr><tr><td>OTLP gRPC</td><td><code>:4317</code></td></tr></tbody></table><p>The metrics generator is enabled and writes service graph and span metrics to Prometheus, powering Grafana&#39;s <strong>Service Map</strong> and <strong>Node Graph</strong> panels.</p><blockquote><p><strong>Kuma mTLS note:</strong> The gRPC OTLP port (4317) is excluded from Kuma sidecar inbound interception (<code>traffic.kuma.io/exclude-inbound-ports: &quot;4317&quot;</code>). Kuma&#39;s MeshTrace plugin sends plain gRPC to Tempo — not mTLS — so the sidecar must not intercept it.</p></blockquote><h3 id="grafana" tabindex="-1">Grafana <a class="header-anchor" href="#grafana" aria-label="Permalink to &quot;Grafana&quot;">​</a></h3><p>Grafana is pre-configured with two datasources:</p><table tabindex="0"><thead><tr><th>Datasource</th><th>URL</th></tr></thead><tbody><tr><td>Prometheus (default)</td><td><code>http://prometheus-server.monitoring.svc.cluster.local:80</code></td></tr><tr><td>Tempo</td><td><code>http://tempo.monitoring.svc.cluster.local:3200</code></td></tr></tbody></table><p>The Tempo datasource has <strong>Service Map</strong> and <strong>Node Graph</strong> enabled, backed by Prometheus for service graph metrics.</p><h2 id="adding-dashboards-via-configmap-sidecar" tabindex="-1">Adding dashboards via ConfigMap sidecar <a class="header-anchor" href="#adding-dashboards-via-configmap-sidecar" aria-label="Permalink to &quot;Adding dashboards via ConfigMap sidecar&quot;">​</a></h2><p>Grafana&#39;s sidecar container watches for ConfigMaps with the label <code>grafana_dashboard=true</code> across all namespaces and automatically loads them as dashboards — no Grafana restart required.</p><p>This allows other showcases to ship their own dashboards independently, without modifying the Grafana Helm values.</p><p><strong>How to add a dashboard:</strong></p><ol><li>Export the dashboard JSON from Grafana (Dashboard → Share → Export → Save to file)</li><li>Create a ConfigMap from the JSON file and label it <code>grafana_dashboard=true</code>:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configmap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-dashboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-namespace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --from-file=my-dashboard.json=my-dashboard.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --dry-run=client</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yaml</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configmap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-dashboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana_dashboard=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>The sidecar picks up the new ConfigMap within seconds and the dashboard appears in Grafana under <strong>Dashboards</strong>.</p><h3 id="example-kuma-service-mesh-dashboard" tabindex="-1">Example: Kuma Service Mesh dashboard <a class="header-anchor" href="#example-kuma-service-mesh-dashboard" aria-label="Permalink to &quot;Example: Kuma Service Mesh dashboard&quot;">​</a></h3><p>The <a href="./kuma.html">Kuma showcase</a> uses this mechanism to register its dashboard. The relevant part of <code>examples/kuma-mesh/setup.sh</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configmap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana-dashboard-kuma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kuma-cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --from-file=kuma-mesh.json=grafana-dashboard-kuma.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --dry-run=client</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yaml</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configmap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana-dashboard-kuma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kuma-cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grafana_dashboard=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --overwrite</span></span></code></pre></div><p>The ConfigMap is created in the <code>kuma-cp</code> namespace — the namespace does not have to be <code>monitoring</code>. Because the Grafana sidecar watches cluster-wide, any labeled ConfigMap is discovered regardless of namespace.</p><h2 id="explore-traces" tabindex="-1">Explore traces <a class="header-anchor" href="#explore-traces" aria-label="Permalink to &quot;Explore traces&quot;">​</a></h2><ol><li>Open <code>https://grafana.example.com:8081</code></li><li>Navigate to <strong>Explore</strong> (compass icon in the left sidebar)</li><li>Select <strong>Tempo</strong> as the datasource</li><li>Use <strong>Search</strong> to browse traces by service name, duration, or status</li><li>Click a trace to see the full span waterfall</li></ol><p>For the <strong>Service Map</strong>, select <strong>Tempo → Service Graph</strong> in Explore to see a live topology of services and their request rates.</p>`,43)])])}const g=s(n,[["render",r]]);export{k as __pageData,g as default};
